using var client = new HttpClient();
var request = new HttpRequestMessage(HttpMethod.Post,
                        "https://api.landr.com/mastering/v1/master/single");

var body = JsonConvert.SerializeObject(new
{
  inputUri = inputUri,
  loudness = "low",
  style = "balanced",
  format = "cd",
});

request.Content =
    new StringContent(body, Encoding.UTF8, "application/json");

request.Headers.Add("x-landr-mastering-api-key", yourApiKey);

var response = await client.SendAsync(request);
var responseStr = await response.Content.ReadAsStringAsync();

const { request } = require('https');
const yourApiKey= 'your-api-key';
const inputUri = 'https://path-to-audio-file.com';

const callback = function (response) {
    var str = '';
    response.on('data', function (chunk) {
        str += chunk;
    });

    response.on('end', function () {
        console.log(str);
    });
};

const req = request(
    {
        host: 'api.landr.com',
        path: '/mastering/v1/master/single',
        headers: {
            'x-landr-mastering-api-key': `${yourApiKey}`,
            'Content-Type': 'application/json',
        },
        method: 'POST',
    },
    callback
);

req.write(
    JSON.stringify({
        inputUri: inputUri,
        loudness: 'low',
        style: 'balanced',
        format: 'cd',
    })
);
req.end();

